### Process Priority (applied at daemon startup)
```rust
use std::io;

/// Apply nice/ionice settings, with platform-specific implementations
pub fn apply_nice_settings(config: &ResourceConfig) -> Result<()> {
    apply_cpu_nice(config.nice_level)?;
    apply_io_priority(&config.io_priority)?;
    Ok(())
}

/// CPU nice: works on both Linux and macOS via libc::nice()
fn apply_cpu_nice(level: i32) -> Result<()> {
    // nice() is POSIX - works on Linux, macOS, BSDs
    let result = unsafe { libc::nice(level) };
    if result == -1 {
        let err = io::Error::last_os_error();
        if err.raw_os_error() != Some(0) {
            tracing::warn!(level, error = %err, "Failed to set nice level");
            return Err(err.into());
        }
    }
    tracing::info!(level = result, "CPU nice level applied");
    Ok(())
}

/// I/O priority: Linux uses ioprio_set, macOS uses setiopolicy_np, others skip
fn apply_io_priority(policy: &IoPriority) -> Result<()> {
    match policy {
        IoPriority::Idle => {
            #[cfg(target_os = "linux")]
            {
                // ioprio_set(IOPRIO_WHO_PROCESS, 0, IOPRIO_CLASS_IDLE << 13)
                let ioprio = (3_i32 << 13) | 0;  // IOPRIO_CLASS_IDLE | priority 0
                let ret = unsafe {
                    libc::syscall(libc::SYS_ioprio_set, 1i32, 0i32, ioprio)
                };
                if ret < 0 {
                    tracing::warn!("ioprio_set failed: {}", io::Error::last_os_error());
                } else {
                    tracing::info!("I/O priority set to idle class (Linux)");
                }
            }
            #[cfg(target_os = "macos")]
            {
                // macOS: Use setiopolicy_np for throttle tier
                // IOPOL_TYPE_DISK = 0, IOPOL_SCOPE_PROCESS = 0, IOPOL_THROTTLE = 3
                let ret = unsafe {
                    libc::syscall(
                        libc::SYS_iopolicysys,
                        0i32,  // IOPOL_CMD_SET
                        0i32,  // IOPOL_TYPE_DISK
                        0i32,  // IOPOL_SCOPE_PROCESS
                        3i32,  // IOPOL_THROTTLE
                    )
                };
                if ret < 0 {
                    tracing::warn!("iopolicysys failed: {}", io::Error::last_os_error());
                } else {
                    tracing::info!("I/O priority set to throttle (macOS)");
                }
            }
            #[cfg(not(any(target_os = "linux", target_os = "macos")))]
            {
                tracing::info!("I/O priority not supported on this platform, skipping");
            }
        }
        IoPriority::BestEffort => { /* default, no action needed */ }
        IoPriority::None => { /* explicitly skip */ }
    }
    Ok(())
}
