### Memory Limits
```rust
use libc::{setrlimit, rlimit, RLIMIT_AS};

struct ResourceLimits {
    max_rss_mb: usize,       // Default: 512MB (configurable)
    max_open_files: u64,     // Default: 256
    max_models_loaded: usize, // Default: 3 (LRU eviction)
}

fn apply_memory_limit(max_mb: usize) -> Result<()> {
    let limit_bytes = (max_mb as u64) * 1024 * 1024;
    let rlim = rlimit { rlim_cur: limit_bytes, rlim_max: limit_bytes };
    let ret = unsafe { setrlimit(RLIMIT_AS, &rlim) };
    if ret != 0 {
        // On macOS, RLIMIT_AS may not be enforced; log warning but continue
        #[cfg(target_os = "macos")]
        tracing::warn!("RLIMIT_AS set but may not be enforced on macOS");
        #[cfg(not(target_os = "macos"))]
        return Err(io::Error::last_os_error().into());
    }
    tracing::info!(max_mb, "Virtual memory limit applied");
    Ok(())
}
