### Thread Pool Sizing
```rust
fn compute_thread_pool_size() -> usize {
    let cpus = num_cpus::get();
    // Never exceed half the cores, max 4 threads
    // This ensures xf daemon never starves interactive processes
    std::cmp::min(4, cpus / 2).max(1)
}
