### Memory Pressure Monitoring (Cross-Platform)
```rust
/// Periodically check system memory usage
/// Platform-specific: /proc/meminfo (Linux), sysctl (macOS)
struct MemoryMonitor {
    check_interval: Duration,    // 5 seconds
    warning_threshold: f64,      // 0.85 (85% system memory used)
    critical_threshold: f64,     // 0.92 (92% - start evicting)
    eviction_policy: EvictionPolicy,
}

enum EvictionPolicy {
    LRU,           // Evict least-recently-used model
    LargestFirst,  // Evict largest model by RSS
}

/// Get system memory usage as fraction (0.0 - 1.0)
fn get_memory_usage() -> Result<f64> {
    #[cfg(target_os = "linux")]
    {
        // Parse /proc/meminfo for MemTotal and MemAvailable
        let content = std::fs::read_to_string("/proc/meminfo")?;
        let total = parse_meminfo_field(&content, "MemTotal")?;
        let available = parse_meminfo_field(&content, "MemAvailable")?;
        Ok(1.0 - (available as f64 / total as f64))
    }
    #[cfg(target_os = "macos")]
    {
        // Use sysctl for total memory + mach_host_info for usage
        use std::process::Command;
        let total_output = Command::new("sysctl")
            .args(["-n", "hw.memsize"])
            .output()?;
        let total: u64 = String::from_utf8_lossy(&total_output.stdout)
            .trim().parse()?;

        // vm_stat gives page-level statistics
        let vm_output = Command::new("vm_stat").output()?;
        let vm_str = String::from_utf8_lossy(&vm_output.stdout);
        let free_pages = parse_vm_stat_field(&vm_str, "Pages free")?;
        let inactive_pages = parse_vm_stat_field(&vm_str, "Pages inactive")?;
        let page_size: u64 = 4096;  // vm_stat reports in pages
        let available = (free_pages + inactive_pages) * page_size;
        Ok(1.0 - (available as f64 / total as f64))
    }
    #[cfg(not(any(target_os = "linux", target_os = "macos")))]
    {
        // Fallback: assume 50% usage (conservative, never evict)
        tracing::warn!("Memory monitoring not supported on this platform");
        Ok(0.5)
    }
}

fn parse_meminfo_field(content: &str, field: &str) -> Result<u64> {
    for line in content.lines() {
        if line.starts_with(field) {
            let kb: u64 = line.split_whitespace()
                .nth(1)
                .ok_or_else(|| anyhow!("Bad meminfo format"))?
                .parse()?;
            return Ok(kb * 1024);  // Convert KB to bytes
        }
    }
    Err(anyhow!("Field {} not found in meminfo", field))
}

#[cfg(target_os = "macos")]
fn parse_vm_stat_field(content: &str, field: &str) -> Result<u64> {
    for line in content.lines() {
        if line.contains(field) {
            let value: u64 = line.split(':')
                .nth(1)
                .ok_or_else(|| anyhow!("Bad vm_stat format"))?
                .trim()
                .trim_end_matches('.')
                .parse()?;
            return Ok(value);
        }
    }
    Err(anyhow!("Field {} not found in vm_stat", field))
}
