### E2E Script (`scripts/daemon/resource_e2e.sh`)
```bash
#!/bin/bash
set -euo pipefail
LOG="tests/e2e/results/resources_$(date +%Y%m%d_%H%M%S).log"
log() { echo "[$(date +%H:%M:%S)] $*" | tee -a "$LOG"; }
PASS=0; FAIL=0

log "=== Resource Management E2E ==="
log "Platform: $(uname -s) $(uname -m)"

# Start daemon with resource limits
log "Starting daemon with max_memory_mb=256, max_models=2..."
XF_DAEMON_MAX_MEMORY_MB=256 XF_DAEMON_MAX_MODELS=2 \
    cargo run --release --bin xf-daemon -- --test-mode &
DAEMON_PID=$!
sleep 2

# Verify daemon is running
kill -0 $DAEMON_PID 2>/dev/null && { log "Daemon running (PID $DAEMON_PID)"; ((PASS++)); } || { log "Daemon failed to start"; ((FAIL++)); exit 1; }

# Check nice level
if [ "$(uname)" = "Linux" ]; then
    NICE=$(awk '{print $19}' /proc/$DAEMON_PID/stat)
    log "Nice level: $NICE (expected 10)"
    [ "$NICE" = "10" ] && ((PASS++)) || ((FAIL++))

    # Check ionice
    IOPRIO=$(cat /proc/$DAEMON_PID/io 2>/dev/null | head -1 || echo "N/A")
    log "I/O priority info: $IOPRIO"
elif [ "$(uname)" = "Darwin" ]; then
    NICE=$(ps -o nice -p $DAEMON_PID | tail -1 | tr -d ' ')
    log "Nice level: $NICE (expected 10)"
    [ "$NICE" = "10" ] && ((PASS++)) || ((FAIL++))
    log "macOS: I/O priority verified via setiopolicy (no proc file)"
    ((PASS++))
fi

# Check thread count
if [ "$(uname)" = "Linux" ]; then
    THREADS=$(ls /proc/$DAEMON_PID/task 2>/dev/null | wc -l)
else
    THREADS=$(ps -M -p $DAEMON_PID | wc -l)
fi
log "Thread count: $THREADS"
EXPECTED_MAX=$(($(nproc 2>/dev/null || sysctl -n hw.ncpu) / 2))
[ "$EXPECTED_MAX" -gt 4 ] && EXPECTED_MAX=4
# Allow some overhead threads (main, tokio runtime, monitor)
[ "$THREADS" -le $((EXPECTED_MAX + 6)) ] && { log "Thread count within bounds"; ((PASS++)); } || { log "Too many threads"; ((FAIL++)); }

# Check RSS at startup
if [ "$(uname)" = "Linux" ]; then
    RSS_KB=$(awk '/VmRSS/ {print $2}' /proc/$DAEMON_PID/status)
else
    RSS_KB=$(ps -o rss -p $DAEMON_PID | tail -1 | tr -d ' ')
fi
log "RSS at startup: ${RSS_KB}KB ($(( RSS_KB / 1024 ))MB)"

# Load a model and check RSS growth
log "Loading test model..."
# (send load request via UDS socket)
echo '{"cmd":"load","model":"test-static"}' | socat - UNIX-CONNECT:/tmp/xf-daemon.sock
sleep 3

if [ "$(uname)" = "Linux" ]; then
    RSS_KB_AFTER=$(awk '/VmRSS/ {print $2}' /proc/$DAEMON_PID/status)
else
    RSS_KB_AFTER=$(ps -o rss -p $DAEMON_PID | tail -1 | tr -d ' ')
fi
log "RSS after model load: ${RSS_KB_AFTER}KB ($(( RSS_KB_AFTER / 1024 ))MB)"

# Verify memory limit respected
RSS_MB_AFTER=$(( RSS_KB_AFTER / 1024 ))
[ "$RSS_MB_AFTER" -le 300 ] && { log "Memory within 256MB+overhead limit"; ((PASS++)); } || { log "WARN: RSS exceeded expected limit: ${RSS_MB_AFTER}MB"; ((FAIL++)); }

# Test model eviction (load 3 models with max_models=2)
log "Testing model eviction (max_models=2)..."
echo '{"cmd":"load","model":"test-model-2"}' | socat - UNIX-CONNECT:/tmp/xf-daemon.sock
sleep 1
echo '{"cmd":"load","model":"test-model-3"}' | socat - UNIX-CONNECT:/tmp/xf-daemon.sock
sleep 2

LOADED=$(echo '{"cmd":"list_models"}' | socat - UNIX-CONNECT:/tmp/xf-daemon.sock)
LOADED_COUNT=$(echo "$LOADED" | jq '.models | length')
log "Models loaded after eviction: $LOADED_COUNT (expected <=2)"
[ "$LOADED_COUNT" -le 2 ] && { log "Model eviction working"; ((PASS++)); } || ((FAIL++))

# Cleanup
log "Stopping daemon..."
kill $DAEMON_PID 2>/dev/null
wait $DAEMON_PID 2>/dev/null || true
log "Daemon stopped"

log "========================="
log "Results: $PASS passed, $FAIL failed"
exit $FAIL
