#[test]
fn test_request_serialization_roundtrip() {
    let requests = vec![
        Request::Health,
        Request::Embed { texts: vec!["hello".into(), "world".into()], model: None, dims: None },
        Request::Rerank { query: "test".into(), documents: vec!["doc1".into()], model: None },
