        Response::Embeddings { vectors: vec![vec![1.0, 2.0, 3.0]], model: "minilm".into() },
        Response::Scores { scores: vec![0.9, 0.5, 0.1], model: "flashrank".into() },
        Response::Health { uptime_secs: 42, models_loaded: vec!["minilm".into()], rss_mb: 128 },
        Response::Status { models: vec![ModelStatus { name: "minilm".into(), loaded: true, size_mb: 80 }] },
        Response::Error { code: 404, message: "model not found".into() },
        Response::Ok,
    ];

    for resp in &responses {
