#[test]
fn test_envelope_framing() {
    let envelope = Envelope {
        version: 1,
        id: 12345,
        payload: rmp_serde::to_vec(&Request::Health).unwrap(),
    };

    // Length-prefixed encoding
    let mut buf = Vec::new();
    let payload = rmp_serde::to_vec(&envelope).unwrap();
    buf.extend_from_slice(&(payload.len() as u32).to_be_bytes());
    buf.extend_from_slice(&payload);

    // Decode
    let len = u32::from_be_bytes(buf[0..4].try_into().unwrap()) as usize;
    let decoded: Envelope = rmp_serde::from_slice(&buf[4..4+len]).unwrap();
    assert_eq!(decoded.version, 1);
    assert_eq!(decoded.id, 12345);
}

#[test]
fn test_large_payload_serialization() {
    // 100 embeddings of 768 dims
    let embeddings: Vec<Vec<f32>> = (0..100)
        .map(|_| (0..768).map(|i| i as f32 * 0.001).collect())
        .collect();
    let resp = Response::Embeddings { vectors: embeddings, model: "nomic".into() };
    let bytes = rmp_serde::to_vec(&resp).unwrap();
    tracing::info!(bytes = bytes.len(), "100x768 embeddings serialized");
    assert!(bytes.len() < 400_000, "Should be compact: {} bytes", bytes.len());

    let decoded: Response = rmp_serde::from_slice(&bytes).unwrap();
    assert_eq!(resp, decoded);
}
