}

#[test]
fn test_lock_file_prevents_duplicate_daemon() {
    let socket_path = temp_socket_path();
    let daemon1 = spawn_test_daemon_sync(&socket_path);

    // Second daemon should detect lock and refuse to start
    let result = try_spawn_daemon(&socket_path);
    assert!(result.is_err(), "Second daemon should fail due to lock");

    daemon1.shutdown();
}

#[test]
fn test_stale_lock_file_detection() {
    let socket_path = temp_socket_path();
    let lock_path = socket_path.with_extension("lock");

    // Create a stale lock file with non-existent PID
    std::fs::write(&lock_path, "999999999\n").unwrap();

    // Daemon should detect stale lock and start anyway
    let daemon = spawn_test_daemon_sync(&socket_path);
    assert!(daemon.is_running());
    daemon.shutdown();
}

#[test]
fn test_lock_file_cleaned_on_shutdown() {
    let socket_path = temp_socket_path();
    let lock_path = socket_path.with_extension("lock");

    let daemon = spawn_test_daemon_sync(&socket_path);
    assert!(lock_path.exists());
    daemon.shutdown();
    std::thread::sleep(Duration::from_millis(100));
    assert!(!lock_path.exists(), "Lock file should be cleaned up");
}

#[test]
fn test_lock_file_recovery_after_crash() {
    let socket_path = temp_socket_path();
    let lock_path = socket_path.with_extension("lock");

    let daemon = spawn_test_daemon_sync(&socket_path);
    let pid = daemon.pid();

    // Kill daemon without graceful shutdown
    unsafe { libc::kill(pid as i32, libc::SIGKILL); }
    std::thread::sleep(Duration::from_millis(100));

    // Next spawn should detect stale lock
    let daemon2 = spawn_test_daemon_sync(&socket_path);
    assert!(daemon2.is_running(), "Should recover from crashed daemon");
    daemon2.shutdown();
}
