    version: u8,      // Protocol version (1)
    id: u64,          // Request ID for correlation
    payload: RequestPayload,
}

enum RequestPayload {
    Health,
    Embed { texts: Vec<String>, model: String, dims: Option<usize> },
    Rerank { query: String, documents: Vec<String>, model: String },
    Shutdown,
    Status, // Returns loaded models, memory usage, uptime
}
