### Core Reranking Step
```rust
// src/search/rerank.rs
use crate::models::{Reranker, ModelRegistry};
use crate::config::ResolvedConfig;

pub struct RerankStep {
    reranker: Box<dyn Reranker>,
    top_k_rerank: usize,   // How many candidates to rerank (default 100)
    min_candidates: usize,  // Skip reranking below this threshold (default 5)
}

impl RerankStep {
    pub fn new(config: &ResolvedConfig, registry: &ModelRegistry) -> Result<Self> {
        let reranker_name = config.reranker.as_deref()
            .unwrap_or(DEFAULT_RERANKER);
        // Uses bd-2crr's convenience method: reranker_by_name()
        let reranker = registry.reranker_by_name(reranker_name)?;

        Ok(Self {
            reranker,
            top_k_rerank: config.rerank_top,
            min_candidates: 5,
        })
    }

    pub fn rerank(&self, query: &str, candidates: &mut Vec<SearchResult>) -> Result<()> {
        if candidates.len() < self.min_candidates {
            tracing::debug!(
                count = candidates.len(),
                min = self.min_candidates,
                "Skipping rerank: too few candidates"
            );
            return Ok(());
        }

        // Only rerank top-K candidates
        let rerank_count = candidates.len().min(self.top_k_rerank);
        let texts: Vec<&str> = candidates[..rerank_count]
            .iter()
            .map(|r| r.text.as_str())
            .collect();

        tracing::info!(
            query = query,
            candidates = rerank_count,
            model = self.reranker.model_name(),
            "Reranking candidates"
        );

        let start = std::time::Instant::now();
        let scores = self.reranker.rerank(query, &texts)?;
        let elapsed = start.elapsed();

        tracing::info!(
            elapsed_ms = elapsed.as_millis(),
            top_score = scores.iter().cloned().fold(f32::NEG_INFINITY, f32::max),
            bottom_score = scores.iter().cloned().fold(f32::INFINITY, f32::min),
            "Reranking complete"
        );

        // Apply reranker scores
        for (i, score) in scores.iter().enumerate() {
            candidates[i].rerank_score = Some(*score);
        }

        // Stable sort: by rerank_score descending, then original score for ties
        candidates[..rerank_count].sort_by(|a, b| {
            let ra = a.rerank_score.unwrap_or(f32::NEG_INFINITY);
            let rb = b.rerank_score.unwrap_or(f32::NEG_INFINITY);
            rb.partial_cmp(&ra)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| {
                    b.score.partial_cmp(&a.score)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
        });

        Ok(())
    }
}
```

